export function resolveFilters(categoryKey: string | null): StaticFilter[] {
  if (!categoryKey) return [...UNIVERSAL_FILTERS]

  const chain: string[] = ['UNIVERSAL']
  const parents = INHERITANCE_MAP[categoryKey]
  if (parents) chain.push(...parents)

  const merged: StaticFilter[] = []
  const seen = new Set<string>()

  for (const key of chain) {
    const filters = key === 'UNIVERSAL' ? UNIVERSAL_FILTERS : (BASE_FILTERS[key] || [])
    for (const f of filters) {
      if (seen.has(f.filter_key)) {
        const idx = merged.findIndex(m => m.filter_key === f.filter_key)
        if (idx !== -1) merged[idx] = f
      } else {
        merged.push(f)
        seen.add(f.filter_key)
      }
    }
  }

  // Add specific filters for this category
  const specific = SPECIFIC_FILTERS[categoryKey] || []
  for (const f of specific) {
    if (seen.has(f.filter_key)) {
      const idx = merged.findIndex(m => m.filter_key === f.filter_key)
      if (idx !== -1) merged[idx] = f
    } else {
      merged.push(f)
      seen.add(f.filter_key)
    }
  }

  return merged.sort((a, b) => a.sort_order - b.sort_order)
}
